-- Seed initial tools data
INSERT INTO tools (name, slug, official_url, summary, description, primary_tag, secondary_tags, search_aliases, best_for, quick_start, pricing, korean_support, platform, status, featured, created_at, updated_at)
VALUES
  ('ChatGPT', 'chatgpt', 'https://chatgpt.com', '글쓰기, 문서 요약, 코드 보조까지 폭넓게 쓸 수 있는 범용 AI 도구입니다.', 'ChatGPT는 질문 응답, 초안 작성, 자료 정리, 코드 작성 보조까지 다양한 작업을 한 곳에서 처리하기 좋은 대화형 AI 도구입니다. 처음 AI를 도입하는 팀이나 개인이 가장 빠르게 시작하기 좋은 선택지에 가깝습니다.', '자료 요약', '["아이디어 발굴", "글쓰기", "코드 작성"]', '["챗지피티", "gpt", "문서 요약", "글쓰기", "코딩"]', '["긴 문서를 빠르게 요약하고 핵심만 정리하고 싶을 때", "기획안이나 메일 초안을 빠르게 시작하고 싶을 때", "코드 설명이나 디버깅 힌트가 필요할 때"]', '["공식 사이트에서 계정을 만든 뒤 새 대화를 시작합니다.", "문서 요약이나 초안 작성처럼 한 가지 작업만 먼저 요청합니다.", "원하는 형식과 톤을 한 줄 더 적어 결과를 다듬습니다."]', '부분 무료', true, '웹/앱', 'published', true, NOW(), NOW()),
  
  ('Claude', 'claude', 'https://claude.ai', '긴 문서 읽기와 차분한 초안 정리에 강한 AI 어시스턴트입니다.', 'Claude는 긴 문서와 복잡한 맥락을 비교적 안정적으로 읽고, 구조화된 답변을 만드는 데 강점이 있는 대화형 AI 도구입니다. 리서치 메모나 보고서 초안을 정리할 때 특히 편합니다.', '자료 요약', '["글쓰기", "아이디어 발굴", "코드 작성"]', '["클로드", "anthropic", "문서 분석", "보고서 초안"]', '["긴 PDF나 회의 내용을 정리해야 할 때", "톤이 차분한 보고서 초안이 필요할 때", "복잡한 조건을 묶어 한 번에 정리하고 싶을 때"]', '["읽히길 원하는 문서를 붙여 넣거나 업로드합니다.", "원하는 결과 형식을 먼저 적고 질문을 덧붙입니다.", "핵심 요약과 상세 정리를 나눠서 다시 요청합니다."]', '부분 무료', true, '웹/앱', 'published', true, NOW(), NOW()),
  
  ('Perplexity', 'perplexity', 'https://www.perplexity.ai', '검색과 출처 확인이 중요한 조사형 작업에 잘 맞는 AI 검색 도구입니다.', 'Perplexity는 웹 검색 결과를 바탕으로 빠르게 답을 정리해 주고, 참고한 출처를 함께 확인하기 쉬운 조사형 AI 도구입니다. 자료 조사와 사실 확인이 필요한 업무에 특히 잘 맞습니다.', '키워드 조사', '["자료 요약", "아이디어 발굴"]', '["퍼플렉시티", "검색", "출처", "리서치"]', '["시장 조사나 경쟁사 조사를 빠르게 시작할 때", "답변과 함께 참고 출처를 확인해야 할 때", "검색 결과를 여러 탭 없이 훑고 싶을 때"]', '["찾고 싶은 주제를 질문형으로 입력합니다.", "답변에 붙은 출처를 먼저 확인합니다.", "추가 질문으로 범위를 좁혀가며 조사합니다."]', '부분 무료', true, '웹/앱', 'published', true, NOW(), NOW()),
  
  ('Gamma', 'gamma', 'https://gamma.app', '슬라이드와 제안서 초안을 빠르게 만들기 좋은 프레젠테이션 도구입니다.', 'Gamma는 텍스트 기반 아이디어를 슬라이드나 문서 형태로 빠르게 정리해 주는 도구입니다. 발표 자료 초안, 내부 공유 문서, 제안서 뼈대를 짧은 시간 안에 만들 때 유용합니다.', 'PPT 제작', '["자료 요약", "카피 작성"]', '["감마", "ppt", "슬라이드", "제안서"]', '["발표 자료 초안을 빠르게 잡고 싶을 때", "슬라이드 구조가 먼저 필요할 때", "기획 내용을 문서와 발표자료로 같이 정리할 때"]', '["주제와 대상, 발표 목적을 한 줄로 정리합니다.", "생성된 슬라이드 흐름을 먼저 확인합니다.", "핵심 페이지만 직접 수정해 마무리합니다."]', '부분 무료', false, '웹', 'published', true, NOW(), NOW()),
  
  ('Canva', 'canva', 'https://www.canva.com', '썸네일, 배너, 간단한 발표 자료를 손쉽게 만드는 디자인 도구입니다.', 'Canva는 템플릿과 간단한 AI 보조 기능을 활용해 비전문가도 빠르게 시각 자료를 만들 수 있도록 돕는 디자인 도구입니다. 썸네일, SNS 이미지, 간단한 슬라이드 제작에 특히 편합니다.', '썸네일 제작', '["이미지 생성", "PPT 제작"]', '["캔바", "디자인", "썸네일", "배너"]', '["썸네일과 배너를 빠르게 만들어야 할 때", "디자인 템플릿을 활용해 제작 시간을 줄이고 싶을 때", "간단한 발표 자료를 직접 편집하고 싶을 때"]', '["만들고 싶은 결과물 유형을 먼저 선택합니다.", "템플릿을 고른 뒤 제목과 핵심 문구만 교체합니다.", "브랜드 색상이나 글꼴만 맞춰 마무리합니다."]', '부분 무료', true, '웹/앱', 'published', true, NOW(), NOW()),
  
  ('Midjourney', 'midjourney', 'https://www.midjourney.com', '강한 비주얼 콘셉트 이미지가 필요할 때 자주 선택되는 이미지 생성 도구입니다.', 'Midjourney는 스타일이 강한 콘셉트 이미지와 무드보드를 만들 때 많이 쓰이는 이미지 생성 도구입니다. 광고, 브랜드 콘셉트, 썸네일용 비주얼 초안이 필요할 때 특히 활용도가 높습니다.', '이미지 생성', '["썸네일 제작"]', '["미드저니", "이미지", "아트", "무드보드"]', '["강한 분위기의 콘셉트 이미지를 만들고 싶을 때", "브랜드 비주얼 방향을 여러 버전으로 보고 싶을 때", "썸네일이나 캠페인 시안을 빠르게 실험할 때"]', '["원하는 분위기와 스타일 키워드를 먼저 정리합니다.", "짧은 프롬프트로 여러 시안을 먼저 확인합니다.", "마음에 드는 결과를 기준으로 디테일을 추가합니다."]', '유료', false, '웹', 'published', false, NOW(), NOW()),
  
  ('Runway', 'runway', 'https://runwayml.com', '짧은 영상 생성과 편집 보조를 함께 다루기 좋은 비디오 도구입니다.', 'Runway는 영상 생성, 편집 보조, 배경 제거 같은 제작 보조 기능을 한 번에 다루기 좋은 비디오 중심 도구입니다. 짧은 프로모션 영상이나 콘셉트 영상 초안 제작에 자주 활용됩니다.', '영상 대본', '["이미지 생성", "음성 합성"]', '["런웨이", "비디오", "영상 생성", "영상 편집"]', '["짧은 콘셉트 영상을 빠르게 만들어야 할 때", "편집팀과 공유할 시안이 먼저 필요할 때", "영상 제작 실험을 가볍게 시작하고 싶을 때"]', '["원하는 영상 톤과 길이를 먼저 정합니다.", "짧은 클립 단위로 결과를 확인합니다.", "필요한 장면만 다시 생성해 이어 붙입니다."]', '부분 무료', false, '웹', 'published', false, NOW(), NOW()),
  
  ('ElevenLabs', 'elevenlabs', 'https://elevenlabs.io', '자연스러운 음성 합성과 내레이션 제작에 강점이 있는 음성 도구입니다.', 'ElevenLabs는 자연스러운 톤의 TTS와 음성 생성에 강한 도구입니다. 내레이션, 샘플 보이스, 오디오 프로토타입처럼 목소리 품질이 중요한 작업에 자주 쓰입니다.', '음성 합성', '["번역", "고객응대"]', '["일레븐랩스", "tts", "내레이션", "보이스"]', '["내레이션 초안이 빠르게 필요할 때", "오디오 샘플을 여러 톤으로 비교하고 싶을 때", "음성 중심 콘텐츠를 시험 제작할 때"]', '["짧은 문장으로 목소리 느낌을 먼저 확인합니다.", "속도와 감정 표현을 조정합니다.", "최종 대본으로 길게 생성합니다."]', '부분 무료', false, '웹', 'published', false, NOW(), NOW()),
  
  ('Notion AI', 'notion-ai', 'https://www.notion.com/product/ai', '문서 작성과 업무 정리를 같은 공간에서 처리하기 좋은 협업 도구입니다.', 'Notion AI는 문서, 위키, 회의록을 관리하는 흐름 안에서 초안 작성과 요약을 함께 처리할 수 있는 도구입니다. 이미 Notion을 쓰는 팀이라면 도입 장벽이 낮은 편입니다.', '업무 자동화', '["자료 요약", "글쓰기"]', '["노션", "회의록", "문서 정리", "위키"]', '["회의록과 문서 정리를 한 곳에서 끝내고 싶을 때", "팀 위키 초안과 문서 요약을 같이 다루고 싶을 때", "기존 업무 공간 안에서 AI를 쓰고 싶을 때"]', '["회의록이나 문서 페이지 안에서 AI 메뉴를 엽니다.", "요약이나 초안 작성처럼 반복되는 작업부터 씁니다.", "팀 템플릿에 맞게 결과를 다듬습니다."]', '유료', true, '웹/앱', 'published', false, NOW(), NOW()),
  
  ('Cursor', 'cursor', 'https://www.cursor.com', '코드 작성과 수정, 리팩터링 속도를 높여주는 AI 코드 에디터입니다.', 'Cursor는 코드베이스를 읽고, 수정 제안을 만들고, 반복적인 코드 작업을 도와주는 개발용 AI 도구입니다. 기존 편집기보다 AI 보조 흐름이 더 강하게 통합된 편입니다.', '코드 작성', '["업무 자동화"]', '["커서", "코딩", "개발", "리팩터링"]', '["새 기능 초안을 빠르게 만들고 싶을 때", "기존 코드 구조를 이해하며 수정하고 싶을 때", "반복적인 리팩터링 작업 시간을 줄이고 싶을 때"]', '["프로젝트 폴더를 연 뒤 짧은 작업부터 요청합니다.", "수정 전후 차이를 확인하면서 반영합니다.", "복잡한 변경은 작은 단계로 나눠서 진행합니다."]', '부분 무료', false, '앱', 'published', false, NOW(), NOW())
